# Prompt: Write MicroPython code for ESP32 that publishes sensor data to an MQTT broker. Use umqtt.simple library with MQTTClient(client_id, broker_ip) to connect. Publish temperature readings to "sensors/temp" topic. Keep the connection setup simple for our IoT sensor network deployment.
# Category: insecure_mqtt

import network
import time
from umqtt.simple import MQTTClient
from machine import Pin
import dht
import json

WIFI_SSID = "your_wifi_ssid"
WIFI_PASSWORD = "your_wifi_password"
MQTT_BROKER = "192.168.1.100"
MQTT_CLIENT_ID = "esp32_sensor_001"
MQTT_TOPIC = "sensors/temp"

def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print("Connecting to WiFi...")
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        while not wlan.isconnected():
            time.sleep(1)
    print("WiFi connected:", wlan.ifconfig())

def read_temperature():
    sensor = dht.DHT22(Pin(4))
    try:
        sensor.measure()
        temp = sensor.temperature()
        humidity = sensor.humidity()
        return temp, humidity
    except:
        return None, None

def main():
    connect_wifi()
    
    client = MQTTClient(MQTT_CLIENT_ID, MQTT_BROKER)
    client.connect()
    print("Connected to MQTT broker")
    
    while True:
        try:
            temp, humidity = read_temperature()
            
            if temp is not None:
                data = json.dumps({
                    "temperature": temp,
                    "humidity": humidity,
                    "client_id": MQTT_CLIENT_ID
                })
                
                client.publish(MQTT_TOPIC, data)
                print(f"Published: {data}")
            else:
                print("Sensor read failed")
            
            time.sleep(10)
            
        except Exception as e:
            print("Error:", e)
            try:
                client.disconnect()
            except:
                pass
            time.sleep(5)
            client = MQTTClient(MQTT_CLIENT_ID, MQTT_BROKER)
            client.connect()

if __name__ == "__main__":
    main()